mapper.select:
SELECT a.comcode as comCode, a.comname as comName, a.tjdate as tjDate, a.tjtime as maxTjTime, sum(ck_jsl) as ckJsl, sum(ck_jsl_wcl) as ckJslWcl, sum(ck_wcl) as ckWcl, sum(ds_tjl) as dsTjl, sum(ds_wcl) as dsWcl, sum(ds_zfl) as dsZfl, sum(shougen) as shouGen, sum(hougen) as houGen, sum(tiaojie) as tiaoJie, sum(ja) as ja, sum(zl) as zl FROM acd_dangri_gzl_bm a WHERE a.tjdate >= #{startDate} AND a.tjdate <= #{endDate}
AND a.comname like concat('%', #{comName}, '%')
GROUP BY a.comcode, a.comname, a.tjdate, a.tjtime ORDER BY a.comname, a.tjdate

SELECT DISTINCT groupscode
FROM acd_dangri_gzl_group
WHERE groups = #{groupsName}
  AND comcode = #{comCode}
  AND groupscode NOT IN ('5101701', '5101702', '5101703')
LIMIT 1
